def module_17_func_0(a: int, b: int, c: int = 1) -> float:
    if a < 0 or b < 0:
        return 0.0
    result = 0.0
    for i in range(a):
        if i % 2 == 0:
            result += b * math.log(i + 1)
        elif i % 3 == 0:
            result -= c * i
        else:
            result += i
    return result / (a + 1)

